253	// Group creates a new inline-Mux with a fresh middleware stack. It's useful
254	// for a group of handlers along the same routing path that use an additional
255	// set of middlewares. See _examples/.
256	func (mx *Mux) Group(fn func(r Router)) Router {
257		im := mx.With().(*Mux)
258		if fn != nil {
259			fn(im)
260		}
261		return im
262	}
