264	// Route creates a new Mux with a fresh middleware stack and mounts it
265	// along the `pattern` as a subrouter. Effectively, this is a short-hand
266	// call to Mount. See _examples/.
267	func (mx *Mux) Route(pattern string, fn func(r Router)) Router {
268		if fn == nil {
269			panic(fmt.Sprintf("chi: attempting to Route() a nil subrouter on '%s'", pattern))
270		}
271		subRouter := NewRouter()
272		fn(subRouter)
273		mx.Mount(pattern, subRouter)
274		return subRouter
275	}
276	
277	// Mount attaches another http.Handler or chi Router as a subrouter along a routing
278	// path. It's very useful to split up a large API as many independent routers and
279	// compose them as a single service using Mount. See _examples/.
280	//
281	// Note that Mount() simply sets a wildcard along the `pattern` that will continue
282	// routing at the `handler`, which in most cases is another chi.Router. As a result,
283	// if you define two Mount() routes on the exact same pattern the mount will panic.
284	func (mx *Mux) Mount(pattern string, handler http.Handler) {
285		if handler == nil {
286			panic(fmt.Sprintf("chi: attempting to Mount() a nil handler on '%s'", pattern))
287		}
288	
289		// Provide runtime safety for ensuring a pattern isn't mounted on an existing
290		// routing pattern.
291		if mx.tree.findPattern(pattern+"*") || mx.tree.findPattern(pattern+"/*") {
292			panic(fmt.Sprintf("chi: attempting to Mount() a handler on an existing path, '%s'", pattern))
293		}
294	
295		// Assign sub-Router's with the parent not found & method not allowed handler if not specified.
296		subr, ok := handler.(*Mux)
297		if ok && subr.notFoundHandler == nil && mx.notFoundHandler != nil {
298			subr.NotFound(mx.notFoundHandler)
299		}
300		if ok && subr.methodNotAllowedHandler == nil && mx.methodNotAllowedHandler != nil {
301			subr.MethodNotAllowed(mx.methodNotAllowedHandler)
302		}
303	
304		mountHandler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
305			rctx := RouteContext(r.Context())
306	
307			// shift the url path past the previous subrouter
308			rctx.RoutePath = mx.nextRoutePath(rctx)
309	
310			// reset the wildcard URLParam which connects the subrouter
311			n := len(rctx.URLParams.Keys) - 1
312			if n >= 0 && rctx.URLParams.Keys[n] == "*" && len(rctx.URLParams.Values) > n {
313				rctx.URLParams.Values[n] = ""
314			}
315	
316			handler.ServeHTTP(w, r)
317		})
318	
319		if pattern == "" || pattern[len(pattern)-1] != '/' {
320			mx.handle(mALL|mSTUB, pattern, mountHandler)
321			mx.handle(mALL|mSTUB, pattern+"/", mountHandler)
322			pattern += "/"
323		}
324	
325		method := mALL
326		subroutes, _ := handler.(Routes)
327		if subroutes != nil {
328			method |= mSTUB
329		}
330		n := mx.handle(method, pattern+"*", mountHandler)
331	
332		if subroutes != nil {
333			n.subroutes = subroutes
334		}
335	}
336	
337	// Routes returns a slice of routing information from the tree,
338	// useful for traversing available routes of a router.
339	func (mx *Mux) Routes() []Route {
340		return mx.tree.routes()
341	}
342	
343	// Middlewares returns a slice of middleware handler functions.
344	func (mx *Mux) Middlewares() Middlewares {
345		return mx.middlewares
346	}
347	
348	// Match searches the routing tree for a handler that matches the method/path.
349	// It's similar to routing a http request, but without executing the handler
350	// thereafter.
351	//
352	// Note: the *Context state is updated during execution, so manage
353	// the state carefully or make a NewRouteContext().
354	func (mx *Mux) Match(rctx *Context, method, path string) bool {
355		m, ok := methodMap[method]
356		if !ok {
357			return false
358		}
359	
360		node, _, h := mx.tree.FindRoute(rctx, m, path)
361	
362		if node != nil && node.subroutes != nil {
363			rctx.RoutePath = mx.nextRoutePath(rctx)
364			return node.subroutes.Match(rctx, method, rctx.RoutePath)
365		}
366	
367		return h != nil
368	}
369	
370	// NotFoundHandler returns the default Mux 404 responder whenever a route
371	// cannot be found.
372	func (mx *Mux) NotFoundHandler() http.HandlerFunc {
373		if mx.notFoundHandler != nil {
374			return mx.notFoundHandler
375		}
376		return http.NotFound
377	}
378	
379	// MethodNotAllowedHandler returns the default Mux 405 responder whenever
380	// a method cannot be resolved for a route.
381	func (mx *Mux) MethodNotAllowedHandler() http.HandlerFunc {
382		if mx.methodNotAllowedHandler != nil {
383			return mx.methodNotAllowedHandler
384		}
385		return methodNotAllowedHandler
386	}
387	
388	// handle registers a http.Handler in the routing tree for a particular http method
389	// and routing pattern.
390	func (mx *Mux) handle(method methodTyp, pattern string, handler http.Handler) *node {
391		if len(pattern) == 0 || pattern[0] != '/' {
392			panic(fmt.Sprintf("chi: routing pattern must begin with '/' in '%s'", pattern))
393		}
394	
395		// Build the computed routing handler for this routing pattern.
396		if !mx.inline && mx.handler == nil {
397			mx.updateRouteHandler()
398		}
399	
400		// Build endpoint handler with inline middlewares for the route
401		var h http.Handler
402		if mx.inline {
403			mx.handler = http.HandlerFunc(mx.routeHTTP)
404			h = Chain(mx.middlewares...).Handler(handler)
405		} else {
406			h = handler
407		}
408	
409		// Add the endpoint to the tree and return the node
410		return mx.tree.InsertRoute(method, pattern, h)
411	}
412	
413	// routeHTTP routes a http.Request through the Mux routing tree to serve
414	// the matching handler for a particular http method.
415	func (mx *Mux) routeHTTP(w http.ResponseWriter, r *http.Request) {
416		// Grab the route context object
417		rctx := r.Context().Value(RouteCtxKey).(*Context)
418	
419		// The request routing path
420		routePath := rctx.RoutePath
421		if routePath == "" {
422			if r.URL.RawPath != "" {
423				routePath = r.URL.RawPath
424			} else {
425				routePath = r.URL.Path
426			}
427			if routePath == "" {
428				routePath = "/"
429			}
430		}
431	
432		// Check if method is supported by chi
433		if rctx.RouteMethod == "" {
434			rctx.RouteMethod = r.Method
435		}
436		method, ok := methodMap[rctx.RouteMethod]
437		if !ok {
438			mx.MethodNotAllowedHandler().ServeHTTP(w, r)
439			return
440		}
441	
442		// Find the route
443		if _, _, h := mx.tree.FindRoute(rctx, method, routePath); h != nil {
444			h.ServeHTTP(w, r)
445			return
446		}
447		if rctx.methodNotAllowed {
448			mx.MethodNotAllowedHandler().ServeHTTP(w, r)
449		} else {
450			mx.NotFoundHandler().ServeHTTP(w, r)
451		}
452	}
453	
454	func (mx *Mux) nextRoutePath(rctx *Context) string {
455		routePath := "/"
456		nx := len(rctx.routeParams.Keys) - 1 // index of last param in list
457		if nx >= 0 && rctx.routeParams.Keys[nx] == "*" && len(rctx.routeParams.Values) > nx {
458			routePath = "/" + rctx.routeParams.Values[nx]
459		}
460		return routePath
461	}
462	
463	// Recursively update data on child routers.
464	func (mx *Mux) updateSubRoutes(fn func(subMux *Mux)) {
465		for _, r := range mx.tree.routes() {
466			subMux, ok := r.SubRoutes.(*Mux)
467			if !ok {
468				continue
469			}
470			fn(subMux)
471		}
472	}
473	
474	// updateRouteHandler builds the single mux handler that is a chain of the middleware
475	// stack, as defined by calls to Use(), and the tree router (Mux) itself. After this
476	// point, no other middlewares can be registered on this Mux's stack. But you can still
477	// compose additional middlewares via Group()'s or using a chained middleware handler.
478	func (mx *Mux) updateRouteHandler() {
479		mx.handler = chain(mx.middlewares, http.HandlerFunc(mx.routeHTTP))
480	}
481	
482	// methodNotAllowedHandler is a helper function to respond with a 405,
483	// method not allowed.
484	func methodNotAllowedHandler(w http.ResponseWriter, r *http.Request) {
485		w.WriteHeader(405)
486		w.Write(nil)
487	}
