func TestDebugWithCORS(t *testing.T) {
	r := NewRouter()
	api := r.WithCORS()
	api.Get("/widgets", func(w http.ResponseWriter, r *http.Request) { w.Write([]byte("ok")) })

	req := httptest.NewRequest("GET", "/widgets", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	if got := w.Header().Get("Access-Control-Allow-Origin"); got != "*" {
		t.Fatalf("expected wildcard origin, got %q", got)
	}
}

func TestDebugEnableCORSWithOptions(t *testing.T) {
	r := NewRouter()
	r.EnableCORSWithOptions(CORSOptions{
		AllowOrigin:      "https://example.com",
